    return user;
  }

  async updateEmailPreferences(id: string, preferences: Partial<Pick<User, 'emailNotificationsEnabled' | 'emailPaymentReminders' | 'emailMaintenanceAlerts' | 'emailLeaseExpiry' | 'emailSystemUpdates'>>): Promise<User | undefined> {
    const [user] = await db
      .update(users)
      .set({
        ...preferences,
        updatedAt: new Date(),
      })
      .where(eq(users.id, id))
      .returning();
    return user || undefined;
  }

  // Notification operations
  async getNotification(id: number): Promise<Notification | undefined> {
    const [notification] = await db.select().from(notifications).where(eq(notifications.id, id));
    return notification || undefined;
  }

  async getAllNotifications(userId: string): Promise<Notification[]> {
    return await db
      .select()
      .from(notifications)
      .where(eq(notifications.userId, userId))
      .orderBy(desc(notifications.createdAt));
  }

  async getUnreadNotifications(userId: string): Promise<Notification[]> {
    return await db
      .select()
      .from(notifications)
      .where(
        and(
          eq(notifications.userId, userId),
          eq(notifications.read, false)
        )
      )
      .orderBy(desc(notifications.createdAt));
  }

  async createNotification(notificationData: InsertNotification): Promise<Notification> {
    const [newNotification] = await db
      .insert(notifications)
      .values({ ...notificationData, createdAt: new Date() })
      .returning();
    return newNotification;
  }

  async markNotificationAsRead(id: number): Promise<boolean> {
    const result = await db
      .update(notifications)
      .set({ read: true, readAt: new Date() })
      .where(eq(notifications.id, id));
    return result.rowCount > 0;
  }

  async markAllNotificationsAsRead(userId: string): Promise<boolean> {
    const result = await db
      .update(notifications)
      .set({ read: true, readAt: new Date() })
      .where(eq(notifications.userId, userId));
    return result.rowCount > 0;
  }

  async deleteNotification(id: number): Promise<boolean> {
    const result = await db
      .delete(notifications)
      .where(eq(notifications.id, id));
    return result.rowCount > 0;
  }

  async getNotificationCount(userId: string): Promise<{ total: number; unread: number }> {
    const total = await db
      .select()
      .from(notifications)
      .where(eq(notifications.userId, userId));

    const unread = await db
      .select()
      .from(notifications)
      .where(
        and(
          eq(notifications.userId, userId),
          eq(notifications.read, false)
        )
      );

    return {
      total: total.length,
      unread: unread.length
    };
  }

  // User management methods
  async approveUser(id: string, approvedBy: string): Promise<User | undefined> {
    const [updatedUser] = await db
      .update(users)
      .set({ 
        status: 'approved', 
        approvedBy,
        approvedAt: new Date(),
        updatedAt: new Date()
      })
      .where(eq(users.id, id))
      .returning();
    return updatedUser;
  }

  async blockUser(id: string): Promise<User | undefined> {
    const [updatedUser] = await db
      .update(users)
      .set({ 
        status: 'blocked',
        updatedAt: new Date()
      })
      .where(eq(users.id, id))
      .returning();
    return updatedUser;
  }

  async deleteUser(id: string): Promise<boolean> {
    const result = await db
      .delete(users)
      .where(eq(users.id, id));
    return result.rowCount > 0;
  }

  async updateUser(id: string, data: Partial<UpsertUser & { password?: string }>): Promise<User | undefined> {
    // Remove password from data if it's empty or undefined
    const updateData = { ...data };
    if (!updateData.password) {
      delete updateData.password;
    }

    const [user] = await db
      .update(users)
      .set({
        ...updateData,
        updatedAt: new Date(),
      })
      .where(eq(users.id, id))
      .returning();
    return user;
  }

  async getUserByEmail(email: string): Promise<User | undefined> {
    const [user] = await db.select().from(users).where(eq(users.email, email));
    return user;
  }

  async createUser(data: {
    firstName: string;
    lastName: string;
    email: string;
    password: string;
    role: string;
    status: string;
  }): Promise<User> {
    // Generate a unique ID for the new user
    const userId = Date.now().toString();

    const [user] = await db
      .insert(users)
      .values({
        id: userId,
        firstName: data.firstName,
        lastName: data.lastName,
        email: data.email,
        role: data.role,
        status: data.status,
        createdAt: new Date(),
        updatedAt: new Date(),
      })
      .returning();
    return user;
  }

  async getPendingUsers(): Promise<User[]> {
    return await db
      .select()
      .from(users)
      .where(eq(users.status, 'pending'))
      .orderBy(desc(users.createdAt));
  }
}

export const storage = new DatabaseStorage();

