import { AircraftWithDetails, UpdateAircraft, updateAircraftSchema } from "@shared/schema";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { formatCurrency, formatDate, getStatusColor } from "@/lib/utils";
import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Maintenance } from "@shared/schema";
import { Check, FileText, Plane, Calendar, Clock, Wrench, Edit, Save, X, Upload, Trash2 } from "lucide-react";
import { AircraftImage } from "@/components/ui/aircraft-image";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";

interface AircraftDetailsModalProps {
  isOpen: boolean;
  onClose: () => void;
  aircraft: AircraftWithDetails;
}

// Helper to get fresh aircraft data
const useFreshAircraft = (aircraft: AircraftWithDetails) => {
  const { data: freshAircraft } = useQuery<AircraftWithDetails[]>({
    queryKey: ["/api/aircraft"],
  });

  return freshAircraft?.find(a => a.id === aircraft.id) || aircraft;
};

export default function AircraftDetailsModal({ isOpen, onClose, aircraft }: AircraftDetailsModalProps) {
  const [activeTab, setActiveTab] = useState("overview");
  const [isEditing, setIsEditing] = useState(false);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string>("");
  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Get fresh aircraft data that updates automatically
  const currentAircraft = useFreshAircraft(aircraft);

  const form = useForm<UpdateAircraft>({
    resolver: zodResolver(updateAircraftSchema),
    defaultValues: {
      registration: currentAircraft.registration,
      make: currentAircraft.make,
      model: currentAircraft.model,
      year: currentAircraft.year,
      status: currentAircraft.status || "available",
      engineType: currentAircraft.engineType || "",
      totalTime: currentAircraft.totalTime || undefined,
      avionics: currentAircraft.avionics || "",
      notes: currentAircraft.notes || "",
      image: currentAircraft.image || "",
    },
  });

  const updateAircraftMutation = useMutation({
    mutationFn: async (data: UpdateAircraft) => {
      const response = await apiRequest("PUT", `/api/aircraft/${aircraft.id}`, data);
      return response.json();
    },
    onSuccess: async (updatedAircraft) => {
      // Invalidate all aircraft-related queries and wait for refetch
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ["/api/aircraft"] }),
        queryClient.invalidateQueries({ queryKey: [`/api/aircraft/${aircraft.id}`] }),
        queryClient.invalidateQueries({ queryKey: [`/api/aircraft/${aircraft.id}/maintenance`] })
      ]);

      // Reset form state
      setIsEditing(false);
      setImageFile(null);
      setImagePreview("");

      toast({
        title: "Success",
        description: "Aircraft updated successfully",
      });
    },
    onError: (error) => {
      console.error("Aircraft update error:", error);
      toast({
        title: "Error",
        description: error instanceof Error ? error.message : "Failed to update aircraft",
        variant: "destructive",
      });
    },
  });

  const { data: maintenanceRecords } = useQuery<Maintenance[]>({
    queryKey: [`/api/aircraft/${aircraft.id}/maintenance`],
    enabled: isOpen && activeTab === "maintenance",
  });

  const { data: documents } = useQuery<any[]>({
    queryKey: [`/api/entity/aircraft/${aircraft.id}/documents`],
    enabled: isOpen && activeTab === "documents",
  });

  const handleClose = () => {
    setIsEditing(false);
    setImageFile(null);
    setImagePreview("");
    form.reset({
      registration: aircraft.registration,
      make: aircraft.make,
      model: aircraft.model,
      year: aircraft.year,
      status: aircraft.status || "available",
      engineType: aircraft.engineType || "",
      totalTime: aircraft.totalTime || undefined,
      avionics: aircraft.avionics || "",
      notes: aircraft.notes || "",
      image: aircraft.image || "",
    });
    onClose();
  };

  const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (file.size > 2 * 1024 * 1024) { // 2MB limit for better performance
      toast({
        title: "Error",
        description: "Image file size must be less than 2MB",
        variant: "destructive",
      });
      return;
    }

    // Check if it's a valid image type
    if (!file.type.startsWith('image/')) {
      toast({
        title: "Error",
        description: "Please upload a valid image file",
        variant: "destructive",
      });
      return;
    }

    setImageFile(file);
    const reader = new FileReader();

    reader.onload = (e) => {
      try {
        const preview = e.target?.result as string;
        if (preview) {
          setImagePreview(preview);
          form.setValue("image", preview);
        }
      } catch (error) {
        console.error("Error setting image preview:", error);
        toast({
          title: "Error",
          description: "Failed to process image",
          variant: "destructive",
        });
      }
    };

    reader.onerror = (error) => {
      console.error("FileReader error:", error);
      toast({
        title: "Error",
        description: "Failed to read image file",
        variant: "destructive",
      });
    };

    try {
      reader.readAsDataURL(file);
    } catch (error) {
      console.error("Error reading file:", error);
      toast({
        title: "Error",
        description: "Failed to read image file",
        variant: "destructive",
      });
    }

    // Clear the file input to allow re-uploading the same file
    if (event.target) {
      event.target.value = '';
    }
  };

  const handleRemoveImage = () => {
    setImageFile(null);
    setImagePreview("");
    form.setValue("image", "");
  };

  const onSubmit = (data: UpdateAircraft) => {
    try {
      // The mutation itself handles async operations and errors
      updateAircraftMutation.mutate(data);
    } catch (error) {
      console.error("Error submitting aircraft update:", error);
      toast({
        title: "Error",
        description: "Failed to submit aircraft update",
        variant: "destructive",
      });
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-[900px] max-h-[90vh] overflow-y-auto" aria-describedby="aircraft-details-description">
        <DialogHeader>
          <div className="flex items-center justify-between">
            <DialogTitle className="text-xl font-sans font-semibold">
              {isEditing ? "Edit Aircraft" : "Aircraft Details"}
            </DialogTitle>
            <p id="aircraft-details-description" className="sr-only">
              {isEditing 
                ? "Edit aircraft information including registration, specifications, and image" 
                : "View detailed aircraft information, maintenance records, and documents"}
            </p>
            <div className="flex space-x-2">
              {isEditing ? (
                <>
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    onClick={() => {
                      setIsEditing(false);
                      form.reset();
                    }}
                  >
                    <X className="h-4 w-4 mr-1" />
                    Cancel
                  </Button>
                  <Button
                    type="submit"
                    size="sm"
                    className="bg-[#3498db] hover:bg-[#2980b9]"
                    disabled={updateAircraftMutation.isPending}
                    onClick={(e) => {
                      e.preventDefault();
                      form.handleSubmit(onSubmit)();
                    }}
                  >
                    <Save className="h-4 w-4 mr-1" />
                    {updateAircraftMutation.isPending ? "Saving..." : "Save"}  
                  </Button>
                </>
              ) : (
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setIsEditing(true)}
                  className="ml-[12px] mr-[12px]"
                >
                  <Edit className="h-4 w-4 mr-1" />
                  Edit
                </Button>
              )}
            </div>
          </div>
        </DialogHeader>

        {isEditing ? (
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
              <div className="flex flex-col md:flex-row gap-6">
                {/* Aircraft image */}
                <div className="w-full md:w-1/3">
                  <FormField
                    control={form.control}
                    name="image"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Aircraft Image</FormLabel>
                        <div className="space-y-3">
                          <FormControl>
                            <Input placeholder="Image URL (optional)" {...field} />
                          </FormControl>

                          <div className="flex gap-2">
                            <Button
                              type="button"
                              variant="outline"
                              size="sm"
                              onClick={() => {
                                const input = document.getElementById('image-upload') as HTMLInputElement;
                                if (input) {
                                  input.value = ''; // Clear previous selection
                                  input.click();
                                }
                              }}
                              className="flex-1"
                            >
                              <Upload className="h-4 w-4 mr-2" />
                              Upload Image
                            </Button>

                            {(field.value || imagePreview) && (
                              <Button
                                type="button"
                                variant="outline"
                                size="sm"
                                onClick={handleRemoveImage}
                                className="text-red-600 hover:text-red-700"
                              >
                                <Trash2 className="h-4 w-4" />
                              </Button>
                            )}
                          </div>

                          <input
                            id="image-upload"
                            type="file"
                            accept="image/*"
                            className="hidden"
                            onChange={handleImageUpload}
                          />
                        </div>
                        <FormMessage /> 
                      </FormItem>
                    )}
                  />
                  <AircraftImage 
                    className="w-full h-48 rounded-lg mt-3" 
                    src={imagePreview || form.watch("image")} 
                    alt={`${aircraft.make} ${aircraft.model}`}
                    fallbackClassName="rounded-lg"
                    key={`edit-${aircraft.id}-${form.watch("image")}`}
                  />
                </div>

                {/* Edit form fields */}
                <div className="w-full md:w-2/3 space-y-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="registration"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Registration</FormLabel>
                          <FormControl>
                            <Input placeholder="N123AB" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="status"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Status</FormLabel>
                          <Select onValueChange={field.onChange} defaultValue={field.value}>
                            <FormControl>
                              <SelectTrigger>
                                <SelectValue placeholder="Select status" />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              <SelectItem value="available">Available</SelectItem>
                              <SelectItem value="leased">Leased</SelectItem>
                              <SelectItem value="maintenance">Maintenance</SelectItem>
                              <SelectItem value="inactive">Inactive</SelectItem>
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="make"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Make</FormLabel>
                          <FormControl>
                            <Input placeholder="Cessna" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="model"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Model</FormLabel>
                          <FormControl>
                            <Input placeholder="172" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="year"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Year</FormLabel>
                          <FormControl>
                            <Input 
                              type="number" 
                              placeholder="2020" 
                              {...field}
                              onChange={(e) => field.onChange(parseInt(e.target.value))}
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="totalTime"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Total Time (hours)</FormLabel>
                          <FormControl>
                            <Input 
                              type="number" 
                              placeholder="1500" 
                              {...field}
                              onChange={(e) => field.onChange(e.target.value ? parseInt(e.target.value) : undefined)}
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="engineType"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Engine Type</FormLabel>
                          <FormControl>
                            <Input placeholder="Lycoming IO-360" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="avionics"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Avionics</FormLabel>
                          <FormControl>
                            <Input placeholder="Garmin G1000" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <FormField
                    control={form.control}
                    name="notes"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Notes</FormLabel>
                        <FormControl>
                          <Textarea 
                            placeholder="Additional information about the aircraft" 
                            className="min-h-[100px]"
                            {...field} 
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
