import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useMutation, useQuery } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Aircraft, Lessee, InsertLease } from "@shared/schema";
import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { format } from "date-fns";
import { CalendarIcon, Plane, Building2, Upload, Link2, X, FileText } from "lucide-react";
import { useState } from "react";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { Calendar } from "@/components/ui/calendar";

interface LeaseFormProps {
  isOpen: boolean;
  onClose: () => void;
}

// Validation schema for the lease form
const leaseFormSchema = z.object({
  aircraftId: z.number({
    required_error: "Aircraft is required",
  }),
  lesseeId: z.number({
    required_error: "Lessee is required",
  }),
  startDate: z.date({
    required_error: "Start date is required",
  }),
  endDate: z.date({
    required_error: "End date is required",
  }),
  monthlyRate: z.string()
    .min(1, "Monthly rate is required")
    .transform(val => parseFloat(val)),
  minimumHours: z.string()
    .min(1, "Minimum hours is required")
    .transform(val => parseInt(val)),
  hourlyRate: z.string()
    .min(1, "Hourly rate is required")
    .transform(val => parseFloat(val)),
  maintenanceTerms: z.string().optional(),
  notes: z.string().optional(),
  status: z.string().default("Active"),
  documentUrl: z.string().optional(),
});

type LeaseFormValues = z.infer<typeof leaseFormSchema>;

export default function LeaseForm({ isOpen, onClose }: LeaseFormProps) {
  const { toast } = useToast();
  const [documentMode, setDocumentMode] = useState<"url" | "file">("url");
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [documentPreview, setDocumentPreview] = useState<string>("");

  // Fetch aircraft and lessees to populate dropdowns
  const { data: aircraft } = useQuery<Aircraft[]>({
    queryKey: ["/api/aircraft"],
    enabled: isOpen,
  });

  const { data: lessees } = useQuery<Lessee[]>({
    queryKey: ["/api/lessees"],
    enabled: isOpen,
  });

  // Set up form with validation
  const form = useForm<LeaseFormValues>({
    resolver: zodResolver(leaseFormSchema),
    defaultValues: {
      aircraftId: undefined,
      lesseeId: undefined,
      startDate: undefined,
      endDate: undefined,
      monthlyRate: "",
      minimumHours: "",
      hourlyRate: "",
      maintenanceTerms: "",
      notes: "",
      status: "Active",
      documentUrl: "",
    }
  });

  // Mutation for creating a new lease
  const createLeaseMutation = useMutation({
    mutationFn: (data: InsertLease) => 
      apiRequest("POST", "/api/leases", data).then(res => res.json()),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/leases"] });
      queryClient.invalidateQueries({ queryKey: ["/api/aircraft"] });
      toast({
        title: "Lease created",
        description: "The lease agreement has been created successfully",
        variant: "default",
      });
      handleClose();
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: `Failed to create lease: ${error.message}`,
        variant: "destructive",
      });
    }
  });

  // Handle file selection
  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      setDocumentPreview(file.name);
    }
  };

  // Convert file to base64 for storage
  const convertFileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  // Reset form and document state when dialog closes
  const handleClose = () => {
    setSelectedFile(null);
    setDocumentPreview("");
    setDocumentMode("url");
    form.reset();
    onClose();
  };

  async function onSubmit(values: LeaseFormValues) {
    try {
      let documentData = values.documentUrl;

      // If file mode and a file is selected, convert to base64
      if (documentMode === "file" && selectedFile) {
        documentData = await convertFileToBase64(selectedFile);
      }

      createLeaseMutation.mutate({
        ...values,
        documentUrl: documentData,
      });
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to process document file",
        variant: "destructive",
      });
    }
  }

  // Filter out already leased aircraft
  const availableAircraft = aircraft?.filter(a => a.status !== "Leased") || [];

  return (
    <Dialog open={isOpen} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-[600px] max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Create Lease Agreement</DialogTitle>
          <DialogDescription>
            Enter the details of the new lease agreement
          </DialogDescription>
        </DialogHeader>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
            <FormField
              control={form.control}
              name="aircraftId"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Aircraft</FormLabel>
                  <Select 
